package com.library.model;

import javax.persistence.*;

/**
 * Book - JPA Entity class mapped to the 'books' table in the H2 database.
 * Exercise 9: Creating a Spring Boot Application
 *
 * JPA Annotations:
 * - @Entity     : Marks this class as a JPA entity (persistent object)
 * - @Table      : Specifies the table name in the database
 * - @Id         : Marks 'id' as the primary key
 * - @GeneratedValue : Auto-generates primary key values (AUTO_INCREMENT)
 * - @Column     : Maps a field to a specific database column
 */
@Entity
@Table(name = "books")
public class Book {

    /** Primary key - auto-generated by the database */
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    /** Title of the book - must not be null */
    @Column(name = "title", nullable = false)
    private String title;

    /** Author of the book - must not be null */
    @Column(name = "author", nullable = false)
    private String author;

    /** ISBN number - must be unique */
    @Column(name = "isbn", unique = true)
    private String isbn;

    /** Publication year */
    @Column(name = "publication_year")
    private Integer publicationYear;

    /** Price of the book */
    @Column(name = "price")
    private Double price;

    // ===== Constructors =====

    /** Default no-args constructor (required by JPA) */
    public Book() {
    }

    /** All-args constructor for convenience */
    public Book(String title, String author, String isbn, Integer publicationYear, Double price) {
        this.title = title;
        this.author = author;
        this.isbn = isbn;
        this.publicationYear = publicationYear;
        this.price = price;
    }

    // ===== Getters and Setters =====

    public Long getId() {
        return id;
    }

    public void setId(Long id) {
        this.id = id;
    }

    public String getTitle() {
        return title;
    }

    public void setTitle(String title) {
        this.title = title;
    }

    public String getAuthor() {
        return author;
    }

    public void setAuthor(String author) {
        this.author = author;
    }

    public String getIsbn() {
        return isbn;
    }

    public void setIsbn(String isbn) {
        this.isbn = isbn;
    }

    public Integer getPublicationYear() {
        return publicationYear;
    }

    public void setPublicationYear(Integer publicationYear) {
        this.publicationYear = publicationYear;
    }

    public Double getPrice() {
        return price;
    }

    public void setPrice(Double price) {
        this.price = price;
    }

    @Override
    public String toString() {
        return "Book{" +
                "id=" + id +
                ", title='" + title + '\'' +
                ", author='" + author + '\'' +
                ", isbn='" + isbn + '\'' +
                ", publicationYear=" + publicationYear +
                ", price=" + price +
                '}';
    }
}
